import { Link, useNavigate } from "react-router-dom";

function Navbar() {
  const navigate = useNavigate();
  const userInfo = JSON.parse(localStorage.getItem("userInfo"));

  const handleLogout = () => {
    localStorage.removeItem("userInfo");
    navigate("/login");
    window.location.reload();
  };

  return (
    <nav style={{ padding: "12px 20px", display: "flex", justifyContent: "space-between", alignItems: "center", background: "#1e1e1e", borderBottom: "1px solid #333" }}>
      <div>
        <Link to="/" style={{ color: "#007bff", marginRight: 15, fontWeight: 600 }}>Home</Link>
        <Link to="/matches" style={{ color: "#007bff", marginRight: 15, fontWeight: 600 }}>Matches</Link>
        <Link to="/players" style={{ color: "#007bff", marginRight: 15, fontWeight: 600 }}>Players</Link>
        <Link to="/teams" style={{ color: "#007bff", marginRight: 15, fontWeight: 600 }}>Teams</Link>
        <Link to="/compare" style={{ color: "#007bff", marginRight: 15, fontWeight: 600 }}>Compare</Link>
        {userInfo && (
          <>
            <Link to="/add-match" style={{ color: "#007bff", marginRight: 15, fontWeight: 600 }}>Add Match</Link>
            <Link to="/add-player" style={{ color: "#007bff", marginRight: 15, fontWeight: 600 }}>Add Player</Link>
            <Link to="/sync-matches" style={{ color: "#27ae60", marginRight: 15, fontWeight: 600 }}>📡 Sync CricAPI</Link>
          </>
        )}
      </div>
      <div>
        {userInfo ? (
          <>
            {userInfo.isAdmin && <Link to="/admin" style={{ color: "white", marginRight: 15, background: '#f57c00', padding: '4px 8px', borderRadius: '4px', fontWeight: 600 }}>Admin</Link>}
            <span style={{ color: "#999", marginRight: 15 }}>Hi, {userInfo.username}</span>
            <button onClick={handleLogout} style={{ background: "#007bff", border: "none", color: "white", padding: "6px 12px", borderRadius: "4px", cursor: "pointer", fontWeight: 600 }}>Logout</button>
          </>
        ) : (
          <>
            <Link to="/login" style={{ color: "#007bff", marginRight: 15, fontWeight: 600 }}>Login</Link>
            <Link to="/register" style={{ color: "white", border: "1px solid #007bff", padding: "5px 10px", borderRadius: "4px", fontWeight: 600, background: "#007bff" }}>Register</Link>
          </>
        )}
      </div>
    </nav>
  );
}

export default Navbar;
